from flask import Flask, session, request, jsonify
import redis
import functools
import time
import json

app = Flask(__name__)
app.secret_key = 'your-secret-key-here'

# Connect to Redis
redis_client = redis.StrictRedis(host='localhost', port=6379, db=0, decode_responses=True)

def cache_result(expiration=300):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Create cache key
            cache_key = f"cache:{func.__name__}:{hash(str(args) + str(kwargs))}"
            
            # Try to get from cache
            cached_result = redis_client.get(cache_key)
            if cached_result:
                return json.loads(cached_result)
            
            # Execute function and cache result
            result = func(*args, **kwargs)
            redis_client.setex(cache_key, expiration, json.dumps(result))
            return result
        return wrapper
    return decorator

@app.route('/login', methods=['POST'])
def login():
    username = request.json.get('username')
    password = request.json.get('password')
    
    # Simulate authentication
    if username and password:
        # Store session in Redis
        session_id = f"session:{username}"
        session_data = {
            'username': username,
            'logged_in': True,
            'timestamp': time.time()
        }
        redis_client.setex(session_id, 3600, json.dumps(session_data))  # 1 hour expiry
        
        return jsonify({'status': 'success', 'message': 'Logged in successfully'})
    return jsonify({'status': 'error', 'message': 'Invalid credentials'}), 401

@app.route('/profile')
def profile():
    # Retrieve session from Redis
    session_id = f"session:{session.get('username', 'anonymous')}"
    session_data = redis_client.get(session_id)
    
    if session_data:
        user_data = json.loads(session_data)
        return jsonify({'user': user_data})
    return jsonify({'error': 'Not authenticated'}), 401

@cache_result(expiration=600)
def expensive_database_query(user_id):
    # Simulate expensive database operation
    time.sleep(2)
    return {'user_id': user_id, 'data': f'Expensive query result for user {user_id}'}

@app.route('/expensive/<int:user_id>')
def get_expensive_data(user_id):
    result = expensive_database_query(user_id)
    return jsonify(result)

if __name__ == '__main__':
    app.run(debug=True)